-- Is the request's authenticated user entitled to this business? (owner-defined so it sees ALL grants)
create or replace function umi.session_can_access_business(p_business uuid)
  returns boolean language sql stable security definer
  set search_path = umi, pg_temp as $$
  select exists (
    select 1 from umi.user_role ur
    where ur.user_id = nullif(current_setting('app.current_user', true), '')::uuid
      and (ur.business_id = p_business or ur.business_id is null)   -- null = platform-wide (superadmin)
  );
$$;
revoke all on function umi.session_can_access_business(uuid) from public;
grant execute on function umi.session_can_access_business(uuid) to api;

-- The ONLY sanctioned way to enter a business context: verifies, then sets the GUC.
create or replace function umi.set_business_context(p_business uuid)
  returns void language plpgsql security definer
  set search_path = umi, pg_temp as $$
begin
  if not umi.session_can_access_business(p_business) then
    raise exception 'access denied: user % not entitled to business %',
      current_setting('app.current_user', true), p_business
      using errcode = 'insufficient_privilege';
  end if;
  perform set_config('app.current_business', p_business::text, true);   -- LOCAL to txn
end $$;
revoke all on function umi.set_business_context(uuid) from public;
grant execute on function umi.set_business_context(uuid) to api;

