    join umi.role_permission rp on rp.role_id = ur.role_id
    join umi.permission p on p.id = rp.permission_id
    where ur.user_id = nullif(current_setting('app.current_user', true), '')::uuid
      and (ur.business_id = current_setting('app.current_business', true)::uuid or ur.business_id is null)
      and p.key = p_key
