-- 60_triggers.sql — intra-tenant referential integrity for cross-tenant-graftable FKs.
create or replace function tenant.tg_assert_customer_same_business()
  returns trigger language plpgsql as $$   -- SECURITY INVOKER (default): the SELECT is under the caller's RLS,
begin                                       -- so a cross-tenant customer is invisible -> EXISTS false -> raise.
  if new.customer_id is not null and not exists (
    select 1 from tenant.customer c where c.id = new.customer_id
  ) then
    raise exception 'customer not found in current business'
      using errcode = 'foreign_key_violation';
  end if;
  return new;
end $$;
