-- 90_rls.sql header addendum:
--   CONTRACT: the umi-api backend MUST set the tenant context with a bound param —
--     select set_config('app.current_business', $1, true)   (or SET LOCAL via a
--     parameterized driver call). NEVER string-interpolate a request value into a
--     SET statement. The `::uuid` cast in every policy below is the DB-side guard:
--     any non-uuid injected value raises invalid_text_representation (fail-closed),
--     and an unset context resolves to NULL -> zero rows.

-- gate_rls_failclosed.sql:
do $$
declare cnt int;
begin
  set local role api;
  -- (a) UNSET context -> NULL uuid -> zero rows (never all-tenants)
  perform set_config('app.current_business', null, true);
  select count(*) into cnt from tenant.customer;
  if cnt <> 0 then raise exception 'RLS not fail-closed: unset context returned % rows', cnt; end if;
  -- (b) EMPTY string -> hard uuid cast error
  perform set_config('app.current_business', '', true);
  begin perform 1 from tenant.customer; raise exception 'RLS not fail-closed: empty context did not error';
  exception when invalid_text_representation then null; end;
  -- (c) GARBAGE -> hard uuid cast error
  perform set_config('app.current_business', 'not-a-uuid', true);
  begin perform 1 from tenant.customer; raise exception 'RLS not fail-closed: garbage context did not error';
  exception when invalid_text_representation then null; end;
  reset role;
end $$;

