  then raise exception 'append-only trigger missing on an audit_log'; end if;
  if exists (select 1 from information_schema.role_table_grants
             where table_name='audit_log' and privilege_type in ('UPDATE','DELETE')
               and grantee not in ('juanlopez1','postgres')) -- owner only
  then raise exception 'a non-owner role holds UPDATE/DELETE on an audit_log'; end if;
end $$;

