// pg.service.ts constructor:
import { readFileSync } from 'node:fs';
const ca = readFileSync(config.get('PG_CA_CERT_PATH', { infer: true }), 'utf8');
const ssl = { ca, rejectUnauthorized: true }; // = sslmode=verify-full with pinned CA
this.app    = new Pool({ connectionString: config.get('DATABASE_URL_APP',    { infer:true }), ssl });
this.worker = new Pool({ connectionString: config.get('DATABASE_URL_WORKER', { infer:true }), ssl });
// (equivalently append ?sslmode=verify-full&sslrootcert=/path/supabase-ca.pem to each URL.)

// onModuleInit — assert TLS actually negotiated on both pools:
for (const [name,pool] of [['app',this.app],['worker',this.worker]] as const) {
  const { rows:[s] } = await pool.query('select ssl from pg_stat_ssl where pid = pg_backend_pid()');
  if (!s?.ssl) throw new Error(`${name} pool is not using TLS`);
}
