-- 99_verify.sql:
do $$ begin
  if exists (select 1 from pg_extension e join pg_namespace n on n.oid=e.extnamespace
             where n.nspname not in ('pg_catalog','extensions'))
  then raise exception 'an extension is installed outside schema extensions'; end if;
  if not exists (select 1 from pg_extension where extname='pg_trgm') then raise exception 'missing pg_trgm'; end if;
