-- 90_rls.sql: least-privilege umi grants for api
revoke select on all tables in schema umi from api;
alter default privileges in schema umi revoke select on tables from api;   -- drop the blanket future-grant (was 90_rls.sql:27)
grant select on umi.role, umi.permission, umi.role_permission, umi.channel_type,
                umi.feature, umi.plan, umi.plan_feature to api;             -- global catalogs stay readable
grant select on umi.effective_entitlement to api;                          -- derived access (view is NOT security_invoker -> runs as owner)
grant select (id,email,full_name,status,last_login_at,created_at,updated_at) on umi.user to api;  -- NOT password_hash/password_algorithm
grant select on umi.user_role to api;   -- RBAC resolution (ideally later scoped by a function on app.current_business/app.user_id)

-- 10_umi.sql: encapsulate credential access so no role can bulk-read hashes
create function umi.lookup_credential(p_email text)
  returns table(user_id uuid, password_hash text, password_algorithm text, status text)
  language sql stable security definer set search_path = umi, pg_temp as $$
    select id, password_hash, password_algorithm, status from umi.user where lower(email)=lower(p_email)
  $$;
revoke all on function umi.lookup_credential(text) from public;
grant execute on function umi.lookup_credential(text) to api;

